def cmd_increase_partitions(admin: KafkaAdminClient, args) -> int:
    if args.total_count < 1:
        raise ValueError("--total-count must be >= 1")
    partition_map = {
        args.topic: NewPartitions(total_count=args.total_count)
    }
    admin.create_partitions(
        topic_partitions=partition_map,
        timeout_ms=args.timeout_ms,
        validate_only=args.validate_only,
    )
    print(json.dumps({
        "status": "ok",
        "action": "increase-partitions",
        "topic": args.topic,
        "total_count": args.total_count,
        "validate_only": args.validate_only,
    }))
    return 0


